"""
push_to_github.py
-----------------
Run this to push all fixed files to GitHub.

Steps:
  1. pip install requests
  2. Get GitHub token: GitHub -> Settings -> Developer settings
                       -> Personal access tokens (classic)
                       -> Generate new token -> tick "repo" -> copy
  3. Paste token below
  4. python push_to_github.py
"""
import base64, requests

GITHUB_TOKEN = "YOUR_GITHUB_TOKEN_HERE"   # <- paste here
REPO_OWNER   = "DushyantIIT"
REPO_NAME    = "ushss_project"
BRANCH       = "main"

FILES_B64 = {'routers/admin.py': '', 'routers/auth.py': '', 'routers/student.py': '', 'routers/faculty.py': '', 'routers/cr.py': '', 'routers/password_reset.py': '', 'app/database.py': '', 'app/deps.py': '', 'app/db.py': ''}

def push(path, b64):
    url = f"https://api.github.com/repos/{REPO_OWNER}/{REPO_NAME}/contents/{path}"
    h = {"Authorization": f"token {GITHUB_TOKEN}", "Accept": "application/vnd.github.v3+json"}
    sha = None
    g = requests.get(url, headers=h, params={"ref": BRANCH})
    if g.status_code == 200:
        sha = g.json().get("sha")
    body = {"message": f"fix: clean unicode + supabase migration {path}", "content": b64, "branch": BRANCH}
    if sha:
        body["sha"] = sha
    r = requests.put(url, headers=h, json=body)
    if r.status_code in (200, 201):
        print(f"  OK  {path}")
    else:
        print(f"  ERR {path} - {r.status_code}: {r.json().get('message')}")

if __name__ == "__main__":
    if GITHUB_TOKEN == "YOUR_GITHUB_TOKEN_HERE":
        print("ERROR: Set your GITHUB_TOKEN first.")
        exit(1)
    print(f"Pushing {len(FILES_B64)} files...\n")
    for p, b in FILES_B64.items():
        push(p, b)
    print("\nDone! Render will redeploy in ~30 seconds.")
